INSERT INTO public.photos VALUES (25936, 'C.â”¬Â¬ de Valencia 1954', 'Imagen capturada en la sureâ”œâ–’a tranviaria terminal de la lâ”œÂ¡nea 15. Casablanca, cuando la unidad 209 entra desde la carretera de Valencia en el bucle establecido alrededor del antiguo bar restaurante El Caserâ”œÂ¡o Aragonâ”œÂ®s (a la izquierda y fuera de plano), para dar la vuelta e iniciar el recorrido de vuelta hacia la norteâ”œâ–’a terminal sita en la plaza de Espaâ”œâ–’a. Este bucle confrontaba con la Fuente de los Incrâ”œÂ®dulos.', 1954, 1954, 1954, 'Anos 50', 'CASABLANCA', 41.62833800, -0.90762700, '0101000020E610000052EE3EC7470BEDBFC26A2C616DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49875294546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49875294546.webp', 'https://www.flickr.com/photos/zaragozaantigua/49875294546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26026, 'Vâ”œÂ¡a de la Hispanidad 1991', 'Foto: Archivo Taumar (Irene Taulâ”œÂ®s y Rafael Margalâ”œÂ®). Vista aâ”œÂ®rea de la Vâ”œÂ¡a Hispanidad, con la Torre de Telecomunicaciones de Telefâ”œâ”‚nica en construcciâ”œâ”‚n. Serâ”œÃ­ inaugurada en 1992, convirtiâ”œÂ®ndose en la estructura mâ”œÃ­s alta de Zaragoza. Su nombre popular es El Pirulâ”œÂ¡, adaptando el de otras instalaciones similares, como la de Torrespaâ”œâ–’a en Madrid. Fuente: www.facebook.com/photo.php?fbid=1798223467068018&set=...', 1991, 1991, 1991, 'Anos 90', 'CASABLANCA', 41.63951000, -0.91322100, '0101000020E61000003FA7203F1B39EDBF84BBB376DBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30014200512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30014200512.webp', 'https://www.flickr.com/photos/zaragozaantigua/30014200512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26069, 'Vâ”œÂ¡a Hispanidad 1994', 'Imagen capturada desde la pronunciada altura de la moderna torre de Telefâ”œâ”‚nica, o "Pirulâ”œÂ¡ de Zaragoza", construida junto a la Vâ”œÂ¡a de la Hispanidad, con una vista dirigida hacia el entronque con ella y mediante rotonda de la avenida de Gâ”œâ”‚mez Laguna. Destaca en el centro de la escena el esqueleto de obra, paralizado desde los aâ”œâ–’os 70, del que tendrâ”œÂ¡a que haber sido Hospital Oncolâ”œâ”‚gico de Zaragoza, cuya colocaciâ”œâ”‚n de la primera piedra en 1973 citâ”œâ”‚ a la hija del entonces Generalâ”œÂ¡simo, al doctor Fernando Cuenca Villoro, y a las principales autoridades locales del Râ”œÂ®gimen. Poco despuâ”œÂ®s esta estructura serâ”œÂ¡a derribada y sustituida por una exclusiva parcela de bloques de viviendas en el nâ”¬â•‘ 54 de la Vâ”œÂ¡a de la Hispanidad. Los solares de primer tâ”œÂ®rmino tambiâ”œÂ®n serâ”œÃ­n urbanizados.', 1994, 1994, 1994, 'Anos 90', 'CASABLANCA', 41.64116000, -0.91396800, '0101000020E61000009BE5B2D1393FEDBF6EC0E78711D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50447493492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50447493492.webp', 'https://www.flickr.com/photos/zaragozaantigua/50447493492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21660, 'Rincâ”œâ”‚n de Goya 1927', 'Imagen capturada durante la construcciâ”œâ”‚n en el parque de Buenavista del Rincâ”œâ”‚n de Goya, segâ”œâ•‘n proyecto del arquitecto Fernando Garcâ”œÂ¡a Mercadal, con el que pretendiâ”œâ”‚ "no honrar a Goya con los manidos recursos: una estatua al pintor, muy bien sentadita en su pedestal esperando el homenaje admirativo de los pazguatos... No. Vanidad, ingenua vanidad, no." Dicho y hecho, esta bocanada de aire fresco arquitectâ”œâ”‚nica fue descalificada por el pazguatismo oficial "de bien" desde que terminaron las obras y fue inaugurado poco despuâ”œÂ®s. Bajo el râ”œÂ®gimen franquista y en 1945 el edificio fue desfigurado hasta hacerlo irreconocible. Tras la recuperaciâ”œâ”‚n de la democracia municipal fue objeto de otra intervenciâ”œâ”‚n en 1995 que supuso una nueva vuelta de tuerca donde se perdiâ”œâ”‚ la gran oportunidad de recuperar su estado original. Una penica.', 1927, 1927, 1927, 'Anos 20', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54121187791.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54121187791.webp', 'https://www.flickr.com/photos/zaragozaantigua/54121187791/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22347, 'Rincâ”œâ”‚n de Goya 1965', 'Foto Gerardo Sancho, 1965. Grupo de muchachas posando en las escaleras de acceso al colegio San Benito, sito en el edificio del Rincâ”œâ”‚n de Goya del parque Primo de Rivera de Zaragoza. Se trata de la clausura de un curso de la Secciâ”œâ”‚n Femenina de la Falange Espaâ”œâ–’ola Tradicionalista y de las Juntas de Ofensiva Nacional Sindicalista, el 21 de junio de 1965. Fuente: Archivo Municipal de Zaragoza.', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20320369991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20320369991.webp', 'https://www.flickr.com/photos/zaragozaantigua/20320369991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23989, 'Miguel Bosâ”œÂ® 1986', 'Foto Elena Casaucau, 1986. Instantâ”œÃ­nea tomada en el Anfiteatro del Rincâ”œâ”‚n de Goya del Parque Grande de Zaragoza, durante un concierto de Miguel Bosâ”œÂ® en 1986. Fuente: www.facebook.com/zgz80s/photos/a.127459403989874.22917.12...', 1986, 1986, 1986, 'Anos 80', 'CASABLANCA', 41.62998900, -0.89930200, '0101000020E6100000CC46E7FC14C7ECBF7DEBC37AA3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18673043303.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18673043303.webp', 'https://www.flickr.com/photos/zaragozaantigua/18673043303/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24018, 'Anfiteatro Rincâ”œâ”‚n de Goya 2006', 'Esta zona del antiguo Rincâ”œâ”‚n de Goya en el Parque de Buenavista, a mediados de la dâ”œÂ®cada de los aâ”œâ–’os 80 conociâ”œâ”‚ una importante intervenciâ”œâ”‚n cuando el arquitecto municipal Ricardo Usâ”œâ”‚n diseâ”œâ–’â”œâ”‚ un auditorio, al aire libre, e inmediato al proyecto original de Garcâ”œÂ¡a Mercadal. Se realizaron nuevos accesos, taquillas, quioscos, escenario, graderâ”œÂ¡o y servicios accesorios, que lo convirtieron en un importante espacio sociocultural para la ciudad del momento. Con el transcurso del tiempo, la apariciâ”œâ”‚n de otros espacios, la intensa circulaciâ”œâ”‚n de la Z-30, entre otras razones, llevaron a su abandono, y acusado deterioro de las instalaciones. En 2005, el Ayuntamiento presentâ”œâ”‚ un proyecto de transformaciâ”œâ”‚n de la zona, que conllevaba desmantelarlo. Se produjeron movilizaciones, recogidas de firmas y apoyos, y un concierto como protesta ante la decisiâ”œâ”‚n, aunque la suerte estaba echada. En la imagen, aspecto de la zona inmediatamente antes del programado derribo. Fuente visual: territoriosonoro.hol.es/', 2006, 2006, 2006, 'Siglo XXI', 'CASABLANCA', 41.63031300, -0.89966500, '0101000020E61000000B630B410ECAECBF309FAC18AED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24564818620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24564818620.webp', 'https://www.flickr.com/photos/zaragozaantigua/24564818620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24050, 'Anfiteatro Rincâ”œâ”‚n de Goya 2006', 'Foto: Juan Carlos Arcos. Aspecto de la ubicaciâ”œâ”‚n del anfiteatro del Rincâ”œâ”‚n de Goya en el parque Primo de Rivera, construido segâ”œâ•‘n proyecto de Ricardo Usâ”œâ”‚n en 1985. Fue derribado en octubre de 2006, y el entorno vuelto a urbanizar como zona verde posteriormente. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CASABLANCA', 41.63029200, -0.89990400, '0101000020E61000004644317903CCECBF18778368ADD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31278814154.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31278814154.webp', 'https://www.flickr.com/photos/zaragozaantigua/31278814154/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24952, 'Rincâ”œâ”‚n de Goya ca. 1927', 'Ilustraciâ”œâ”‚n del Rincâ”œâ”‚n de Goya del parque de Buenavista, proyectado por Fernando Garcâ”œÂ¡a Mercadal en 1926 e inaugurado en 1928. Este dibujo formaba parte de una colecciâ”œâ”‚n de postales editadas por la tipogrâ”œÃ­fica del Heraldo de Aragâ”œâ”‚n, con diversas localizaciones de Zaragoza. Fuente: www.todocoleccion.net', 1927, 1927, 1927, 'Anos 20', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36770161586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36770161586.webp', 'https://www.flickr.com/photos/zaragozaantigua/36770161586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25074, 'Ramâ”œâ”‚n Acâ”œÂ¡n 1930', '"Ramâ”œâ”‚n Acâ”œÂ¡n, sentado junto a sus esculturas en el Rincâ”œâ”‚n de Goya". En la primavera de 1930 se organizâ”œâ”‚ en el "Rincâ”œâ”‚n de Goya" una exposiciâ”œâ”‚n del multifacâ”œÂ®tico artista oscense Ramâ”œâ”‚n Acâ”œÂ¡n con esculturas, maquetas, impresos y pinturas. En la imagen, capturada en el interior del edificio diseâ”œâ–’ado por Fernando Garcâ”œÂ¡a Mercadal, las obras "Bailadera", "Baâ”œâ–’ista" y "Maqueta para un monumento a la Paz", ademâ”œÃ­s de una jaula con pajarita encerrada, posan junto al sedente autor. Unos meses despuâ”œÂ®s, Acâ”œÂ¡n se involucrarâ”œÃ­ en la Sublevaciâ”œâ”‚n de Jaca, aunque su fracaso le hizo exiliarse a Francia. Regresâ”œâ”‚ tras el 14 de abril de 1931, y siguiâ”œâ”‚ compaginando sus actividades artâ”œÂ¡sticas (entre ellas, "producir" la pelâ”œÂ¡cula de Luis Buâ”œâ–’uel "Las Hurdes, tierra sin pan"), con su militancia anarquista. Tras el 18 de julio de 1936, fue asesinado por los golpistas de Huesca. Fuente: Foto Abelardo de la Barrera, en servicios3.aragon.es/', 1930, 1930, 1930, 'Anos 30', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19978071214.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19978071214.webp', 'https://www.flickr.com/photos/zaragozaantigua/19978071214/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22100, 'Escuela infantil Casablanca 1955', 'Grupo de niâ”œâ–’os y niâ”œâ–’as posando con su maestra doâ”œâ–’a Paquita en la Escuela Infantil del barrio de Casablanca, sita en la manzana entre la calle del Embarcadero (antigua de la Ermita) y de las Escuelas, hacia 1955. Fuente visual: Nuria Asâ”œÂ¡n Garcâ”œÂ¡a, "Recuerdos de Casablanca", Ediciones 94, (2015).', 1955, 1955, 1955, 'Anos 50', 'CASABLANCA', 41.62974900, -0.90728400, '0101000020E6100000DAE385747808EDBF27D87F9D9BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20439782495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20439782495.webp', 'https://www.flickr.com/photos/zaragozaantigua/20439782495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22291, 'Vâ”œÂ¡a Hispanidad 1969', 'Imagen de la gasolinera de Casablanca, junto a la Vâ”œÂ¡a Hispanidad (izquierda), y el desemboque de la calle La Vâ”œÂ¡a en ella (donde el cartel publicitario). Esta calle recuerda, de alguna forma, el antiguo trazado de la lâ”œÂ¡nea de Cariâ”œâ–’ena a Zaragoza por estos lares, hasta su desmantelamiento en los aâ”œâ–’os 30. Al fondo, los enormes bloques de Isabel la Catâ”œâ”‚lica. A la derecha, los â”œâ•‘ltimos bloques del comienzo de la Vâ”œÂ¡a Hispanidad. Fuente visual: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CASABLANCA', 41.63346300, -0.90829200, '0101000020E610000065FD6662BA10EDBFEF1CCA5015D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259370703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259370703.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259370703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22847, 'Rincâ”œâ”‚n de Goya c.1982', 'Edificio del Rincâ”œâ”‚n de Goya, en los aâ”œâ–’os 80. Fuente: www.facebook.com/photo.php?fbid=998861186796393&set=o...', 1982, 1982, 1982, 'Anos 80', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15149704803.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15149704803.webp', 'https://www.flickr.com/photos/zaragozaantigua/15149704803/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22859, 'Isabel la Catâ”œâ”‚lica 1987', 'Luis Mâ”œÂ¡nguez. 1987. Imagen del paseo de Isabel la Catâ”œâ”‚lica desde la torre-mirador de la Feria de Muestras. Al fondo, encuentro de este paseo con la Vâ”œÂ¡a de la Hispanidad en la denominada "Rotonda ciudad de Toulouse", donde una escultura de â”œÃ¼ngel Orensanz (aquâ”œÂ¡ tapada por los â”œÃ­rboles) celebra el bimilenario de la ciudad. En el arranque de la Vâ”œÂ¡a Ibâ”œÂ®rica, visual del inicio del barrio de Casablanca. A la izquierda, los gigantes desarrollistas, y un pedacito del Instituto "Miguel Catalâ”œÃ­n". A la derecha, un poco antes, el nuevo convento de Jerusalen, trasplantado en 1946 desde el paseo de la Independencia a un entorno en el que pronto quedâ”œâ”‚ como una miniatura constructiva. Este paseo era la entrada/salida natural a la ciudad desde la carretera de Valencia, con todo lo que ello suponâ”œÂ¡a.', 1987, 1987, 1987, 'Anos 80', 'CASABLANCA', 41.63400000, -0.90307800, '0101000020E61000003A9677D503E6ECBFFED478E926D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15648197229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15648197229.webp', 'https://www.flickr.com/photos/zaragozaantigua/15648197229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22903, 'Anfiteatro del Rincâ”œâ”‚n de Goya 1989', 'Desde el inicio de los aâ”œâ–’os 80 se celebraban conciertos en una natural ladera cercana al edificio del Rincâ”œâ”‚n de Goya, y a mediados de la dâ”œÂ®cada, durante la eclosiâ”œâ”‚n de la movida, el Ayuntamiento decidiâ”œâ”‚ construir allâ”œÂ¡ el llamado Anfiteatro, con proyecto Ricardo Usâ”œâ”‚n Garcâ”œÂ¡a y como escenario estable de representaciones y actuaciones al aire libre, sobre todo en las tardes y noches del verano. Por â”œÂ®l pasaron algunas seâ”œâ–’eras figuras y grupos de la escena musical contemporâ”œÃ­nea. En la imagen aparecen tambiâ”œÂ®n las gradas aâ”œâ–’adidas a posteriori. Fue desmantelado en 2007 tras un perâ”œÂ¡odo de abandono y degradaciâ”œâ”‚n, cuando ya hacâ”œÂ¡a tiempo que el paso del Cinturâ”œâ”‚n de Ronda, a espaldas del fotâ”œâ”‚grafo, con sus severas afecciones acâ”œâ•‘sticas habâ”œÂ¡a sentenciado la continuidad de este enclave. Desde entonces perdura como una accidentada extensiâ”œâ”‚n del actual Parque Grande Josâ”œÂ® Antonio Labordeta.', 1989, 1989, 1989, 'Anos 80', 'CASABLANCA', 41.62998900, -0.89930200, '0101000020E6100000CC46E7FC14C7ECBF7DEBC37AA3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21487482990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21487482990.webp', 'https://www.flickr.com/photos/zaragozaantigua/21487482990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22945, 'P.â”¬â•‘ de Isabel la Catâ”œâ”‚lica c.1985', 'Aâ”œÂ®rea visual sobre la gran rotonda en la que confluâ”œÂ¡an el final paseo de Isabel la Catâ”œâ”‚lica y el arranque de la Vâ”œÂ¡a Hispanidad y la Vâ”œÂ¡a Ibâ”œÂ®rica. En la rotonda destaca la representaciâ”œâ”‚n alegâ”œâ”‚rica "Bimilenario" realizada por el escultor â”œÃ¼ngel Orensanz. En primer tâ”œÂ®rmino, el cuartel de Sanidad. Fuente visual: AMZ.', 1985, 1985, 1985, 'Anos 80', 'CASABLANCA', 41.63223800, -0.90515800, '0101000020E6100000FFCEF6E80DF7ECBFECA4BE2CEDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37831864185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37831864185.webp', 'https://www.flickr.com/photos/zaragozaantigua/37831864185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23483, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1960', 'Dibujo del nuevo colegio de Santo Tomâ”œÃ­s de Aquino abierto en el paseo de Ruiseâ”œâ–’ores tras el cierre del prâ”œÂ¡stino colegio de la calle del Buen Pastor. La que fuera original "Villa Rosita" al principio del siglo XX se encaminâ”œâ”‚ a su sexta dâ”œÂ®cada de existencia bien distinta de la que fuera diseâ”œâ–’ada por Manuel Isasi Isasmendi. A la izquierda, las empinadas escaleras de acceso al patio de recreo. A la derecha, fachada e ingreso principal donde destaca el esquinero torreâ”œâ”‚n de aires modernistas. Este colegio cerrarâ”œÂ¡a sus puertas en 1986 y serâ”œÂ¡a vendido a una constructora. En consecuencia, las instalaciones fueron remodeladas aâ”œâ–’os despuâ”œÂ®s para exclusivas viviendas, e incluso se habilitâ”œâ”‚ un espacio para una fantasmagâ”œâ”‚rica "Fundaciâ”œâ”‚n Manuel Labordeta". Fuente visual: "Grabado en la mente. Historia del Colegio Santo Tomaâ• Ã¼s Aquino de Zaragoza", Santiago Sancho Vallestâ”œÂ¡n.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63651000, -0.88907700, '0101000020E61000007D06D49B5173ECBFDAC9E02879D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44612525065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44612525065.webp', 'https://www.flickr.com/photos/zaragozaantigua/44612525065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24933, 'Rincâ”œâ”‚n de Goya 1928', 'El Rincâ”œâ”‚n de Goya, cuyo proyecto de Fernando Garcâ”œÂ¡a Mercadal data de 1926, es obra pionera de la arquitectura moderna en Espaâ”œâ–’a. Finalizado en 1928, estaba dedicado a conmemorar a Goya, en una zona de especial recogimiento, en un jardâ”œÂ¡n dentro de un anfiteatro natural, bordeado por el râ”œÂ¡o Huerva, que pasaba cerca de Fuendetodos, y que ejercâ”œÂ¡a de nexo de uniâ”œâ”‚n entre este lugar, y Zaragoza. Pero lo que los câ”œÃ­nones, la tradiciâ”œâ”‚n y el consenso esperaban (una figura de Goya con paleta y pincel, y acompaâ”œâ–’ado por la tropa aragonesa), se convierte en un edificio abierto a un jardâ”œÂ¡n, con una biblioteca y un museo sobre la vida y obra del pintor. La prensa del momento, ejerciendo de la voz de su amo, oscilâ”œâ”‚ entre rogar que la vegetaciâ”œâ”‚n creciera deprisa para tapar el engendro, o esperar a que alguien lo abriera para dejar salir la estatua que contenâ”œÂ¡a dentro. La sociedad del orden echâ”œâ”‚ sobre â”œÂ®l un velo de olvido, que continâ”œâ•‘a en nuestros dâ”œÂ¡as, ademâ”œÃ­s de transformarlo hasta dejarlo irreconocible. Pasâ”œâ”‚ el 250 aniversario del natalicio de Goya, y no pasâ”œâ”‚ nada. A ver en el aniversario 275. Fuente: "Luces de la ciudad. Arte y Cultura en Zaragoza. 1914-1936", aâ”œâ–’o 1995.', 1928, 1928, 1928, 'Anos 20', 'CASABLANCA', 41.63048000, -0.89870600, '0101000020E6100000DA01D71533C2ECBF1B649291B3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15313189589.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15313189589.webp', 'https://www.flickr.com/photos/zaragozaantigua/15313189589/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24935, 'Rincâ”œâ”‚n de Goya 1928', 'Imagen de la inauguraciâ”œâ”‚n oficial del "Rincâ”œâ”‚n de Goya", que tuvo lugar el 16 de abril de 1928, dentro d elos actos de conmemoraciâ”œâ”‚n del centenario de la muerte de Francisco Goya. Fue diseâ”œâ–’ado por Fernando Garcâ”œÂ¡a Mercadal, en el entorno ordenado a su alrededor del Parque de Buena Vista. Al acto de inauguraciâ”œâ”‚n asistieron autoridades militares, religiosas, y algunas civiles como el Alcalde y el Gobernador Civil, con amenizaciâ”œâ”‚n musical a cargo de "la Banda del Hospicio", que interpretâ”œâ”‚ obras de la â”œÂ®poca (de Goya). En aquâ”œÂ®l momento se pensaba destinar el edificio a "Biblioteca", y el entorno, "a lugar de evocaciâ”œâ”‚n de la memoria del pintor". Quâ”œÂ® cosas. Fuente visual: Foto Palacio para "Aragâ”œâ”‚n : revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o V, Nâ”¬â•‘ 42, marzo 1929).', 1928, 1928, 1928, 'Anos 20', 'CASABLANCA', 41.63049700, -0.89878400, '0101000020E6100000C860C5A9D6C2ECBFF19C2D20B4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15487156048.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15487156048.webp', 'https://www.flickr.com/photos/zaragozaantigua/15487156048/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24939, 'Rincâ”œâ”‚n de Goya 1928', '"Jardines denominados Rincâ”œâ”‚n de Goya, en Zaragoza, que se inaugurarâ”œÃ­n con motivo del Centenario". Fuente visual: foto Vidal, en "La Esfera", 21 de abril de 1928.', 1928, 1928, 1928, 'Anos 20', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20025226882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20025226882.webp', 'https://www.flickr.com/photos/zaragozaantigua/20025226882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25092, 'Rincâ”œâ”‚n de Goya 1930', 'Imagen capturada en el interior del original y vilipendiado edificio del Rincâ”œâ”‚n de Goya en el Parque de Buenavista, con Juan Josâ”œÂ® Luis Gonzâ”œÃ­lez Bernal, pintor local vanguardista vinculado con la corriente surrealista radical, posando junto a un muestrario de los â”œâ”‚leos, dibujos y guaches que allâ”œÂ¡ exponâ”œÂ¡a. Fuente visual: "Andalâ”œÃ­n, periâ”œâ”‚dico quincenal aragonâ”œÂ®s".', 1930, 1930, 1930, 'Anos 30', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32630953135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32630953135.webp', 'https://www.flickr.com/photos/zaragozaantigua/32630953135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25629, 'Pedro IV 1974', 'Imagen del nuevo polâ”œÂ¡gono Romareda, centrada en el bloque en construcciâ”œâ”‚n del nâ”¬â•‘ 4 de la calle de Pedro IV el Ceremonioso. A la izquierda, la calle de Juan II de Aragâ”œâ”‚n, donde destaca el bloque del nâ”¬â•‘ 8 de esa calle, y comienzan a emerger en superficie, junto a â”œÂ®l, los andamios de obra del futuro nâ”¬â•‘ 6 de Pedro IV. La captura se ha realizado, posiblemente, desde las alturas de la torre con el nâ”¬â•‘ 5 del paseo de Isabel la Catâ”œâ”‚lica. Fuente visual: diario "El Noticiero". Archivo Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n Miguel.', 1974, 1974, 1974, 'Anos 70', 'CASABLANCA', 41.63392200, -0.90433200, '0101000020E61000009F3D97A949F0ECBF821B295B24D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33564088612.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33564088612.webp', 'https://www.flickr.com/photos/zaragozaantigua/33564088612/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25634, 'Vista suroeste 2011', 'Vista aâ”œÂ®rea del eje suroeste de Zaragoza, desde el paseo de Isabel la Catâ”œâ”‚lica hasta Valdespartera, pasando por la Vâ”œÂ¡a Ibâ”œÂ®rica, en abril de 2011. Fuente: Paisajes urbanos residenciales en la Zaragoza contemporâ”œÃ­nea, Universidad de Zaragoza, 2012.', 2011, 2011, 2011, 'Siglo XXI', 'CASABLANCA', 41.63265600, -0.90521300, '0101000020E6100000E23FDD4081F7ECBF20CF2EDFFAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40646860472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40646860472.webp', 'https://www.flickr.com/photos/zaragozaantigua/40646860472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21815, 'Radio Zaragoza 1938', 'Portada de un folleto propagandâ”œÂ¡stico de Radio Zaragoza de FET y de las JONS (EAJ 101), realizado en el III aâ”œâ–’o Triunfal, tras la inauguraciâ”œâ”‚n del nuevo complejo emisor situado en la parte alta de Casablanca, junto al Canal Imperial, representado con un dibujo decorado con sendas y coloristas banderas de la Espaâ”œâ–’a nacionalista, y de Falange. A su lado, un recorte fotogrâ”œÃ­fico del Pilar, cuyas torres equilibran las monumentales antenas que permitâ”œÂ¡an llegar a las ondas hasta el estado norteamericano de Massachusetts. Otro recorte de la puerta del Carmen, completa la composiciâ”œâ”‚n, que es coronada hâ”œÃ­bilmente por un micrâ”œâ”‚fono de la emisora, a modo de subliminal sâ”œÂ¡mil mariano. Fuente visual: www.todocoleccion.net/', 1938, 1938, 1938, 'Anos 30', 'CASABLANCA', 41.63556600, -0.91609100, '0101000020E6100000321EA5129E50EDBF8A39083A5AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30805857222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30805857222.webp', 'https://www.flickr.com/photos/zaragozaantigua/30805857222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21869, 'Canal Imperial 1935', 'Imagen capturada durante el paso del ferrocarril de Caminreal por el reciente puente construido sobre el Canal Imperial, en territorio de Miralbueno el Viejo y muy cerca de los depâ”œâ”‚sitos de agua de Casablanca (al fondo). Hacia la derecha, y tras cruzar el Canal, el recorrido lleva hacia Valdespartera, donde el tendido gira hasta ponerse en paralelo a la carretera de Zaragoza a Valencia. Fuente visual: Revista Blanco y Negro.', 1935, 1935, 1935, 'Anos 30', 'CASABLANCA', 41.63594000, -0.92283000, '0101000020E6100000D690B8C7D287EDBFEF1B5F7B66D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36520625422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36520625422.webp', 'https://www.flickr.com/photos/zaragozaantigua/36520625422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24813, 'Arrabal c.1900', 'â”œÃ´leo de Leopoldo Albesa. Vista de la entrada de la calle Sobrarbe en el barrio del Arrabal, desde el puente de Piedra. Fuente: Heraldo de Aragâ”œâ”‚n.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65798400, -0.87492500, '0101000020E6100000567DAEB662FFEBBF48A5D8D138D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39310535830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39310535830.webp', 'https://www.flickr.com/photos/zaragozaantigua/39310535830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22039, 'Franco 1953', 'Ayuntamiento de Zaragoza/Marâ”œÂ¡n Chivite. 21 junio 1953. "Despuâ”œÂ®s de su recorrido triunfal por tierras de las tres provincias aragonesas, el Jefe del Estado, acompaâ”œâ–’ado de su esposa, permaneciâ”œâ”‚ casi dos dâ”œÂ¡as en nuestra ciudad, en los que tuvo ocasiâ”œâ”‚n de visitar los principales edificios oficiales que han sido construidos en estos â”œâ•‘ltimos aâ”œâ–’os, los depâ”œâ”‚sitos de abastecimiento de aguas y estaciâ”œâ”‚n de coagulaciâ”œâ”‚n y admirar el desarrollo urbanâ”œÂ¡stico de Zaragoza. Preocupaciâ”œâ”‚n preferente del Caudillo y de su esposa fuâ”œÂ® (sic) la visita al templo del Pilar, para adorar a la Virgen, a la que tantas veces se encomendâ”œâ”‚ y pidiâ”œâ”‚ su protecciâ”œâ”‚n el Generalâ”œÂ¡simo durante la Cruzada espaâ”œâ–’ola, que tan victoriosamente supo ganar a los enemigos de Espaâ”œâ–’a. En la Diputaciâ”œâ”‚n Provincial fueron obsequiados los insignes huâ”œÂ®spedes con una cena de gala, y por todas partes el pueblo de Zaragoza les hizo objeto de las mâ”œÃ­s entusiastas aclamaciones." Revista "Aragâ”œâ”‚n", Sindicato de Iniciativa y Propaganda, nâ”œâ•‘m. 227, abril-junio 1953. En la imagen, el Jefe del Estado, Franco, disfrazado de civil visita los nuevos depâ”œâ”‚sitos de agua de Casablanca, acompaâ”œâ–’ado por el camisa azul bajo chaqueta blanca y Alcalde de la ciudad, Josâ”œÂ® Marâ”œÂ¡a Garcâ”œÂ¡a Belenguer (de 1949 a 1954).', 1953, 1953, 1953, 'Anos 50', 'CASABLANCA', 41.63436900, -0.91677900, '0101000020E6100000501BD5E94056EDBF514CDE0033D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14732077209.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14732077209.webp', 'https://www.flickr.com/photos/zaragozaantigua/14732077209/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23387, 'Embarcadero de Valdefierro 2008', 'Construcciâ”œâ”‚n del embarcadero del Canal Imperial de Aragâ”œâ”‚n en el barrio de Valdefierro, junto al cruce de las calles Centauro y Casiopea. La obra se enmarcaba en un plan abortado para volver a hacer navegable el Canal en Zaragoza, con cuatro embarcaderos: â”œÂ®ste, el de la calle â”œÃ¼frica, el de La Paz y el de los depâ”œâ”‚sitos de Casablanca, esclusa incluida. Todo ello en el marco del plan de riberas de la Expo 2008. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.63475000, -0.93335700, '0101000020E6100000F8C3CF7F0FDEEDBF6891ED7C3FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31899317773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31899317773.webp', 'https://www.flickr.com/photos/zaragozaantigua/31899317773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23413, 'Suroeste 2001', 'Ortofoto de los terrenos en que se irâ”œÃ­n construyendo los nuevos barrios del suroeste de Zaragoza. En la imagen, ya edificado el de Montecanal, al sur de Valdefierro y el Canal Imperial de Aragâ”œâ”‚n. A la izquierda, el futuro Arcosur; al norte, lo que serâ”œÃ­ Rosales del Canal; al este, Valdespartera. Rodea sinuoso por el sur el trazado del hoy terminado Cuarto Cinturâ”œâ”‚n o Z-40. Fuente visual: www.nacionrotonda.com/', 2001, 2001, 2001, 'Siglo XXI', 'CASABLANCA', 41.62974000, -0.94912300, '0101000020E61000007F349C32375FEEBFD47D00529BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25656822895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25656822895.webp', 'https://www.flickr.com/photos/zaragozaantigua/25656822895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23721, 'Enlace de Carreteras 1965', 'Vista aâ”œÂ®rea sobre el Enlace de Carreteras en un dâ”œÂ¡a de poco trâ”œÃ­fico, poco antes de su redenominaciâ”œâ”‚n como Vâ”œÂ¡a de la Hispanidad. En primer plano, las instalaciones de ARVIN, Aragonesa Vinâ”œÂ¡cola, S.A., planta embotelladora de caldos provenientes de cooperativas de la provincia, esquinera con el serpenteante y albino camino del Terminillo, que viene de cruzarse, poco antes, con el camino de la Mosquetera. Al fondo, el telâ”œâ”‚n edilicio del suroeste de la ciudad, delimitado por el colegio Mayor Pedro Cerbuna, la Hâ”œÂ¡pica, el cuartel de Palafox, la Feria de Muestras, y el estadio municipal de la Romareda. Confrontaban con la embotelladora, al otro lado del enlace de Carreteras, los depâ”œâ”‚sitos de agua de Casablanca, y justo a su izquierda, una recta fila de seâ”œâ–’alados mojones anuncia la inminencia de la prolongaciâ”œâ”‚n hasta estos lares de la avenida de San Juan Bosco, pronto denominada alcalde Gâ”œâ”‚mez Laguna. Fuente visual: Arxiu Nacional de Catalunya.', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.64009600, -0.91379500, '0101000020E61000003DF20703CF3DEDBF74266DAAEED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31730563856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31730563856.webp', 'https://www.flickr.com/photos/zaragozaantigua/31730563856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21074, 'Sindicato de Riego de Miraflores 1871', '"Plano catastral de las fincas que en el Canal Imperial de Aragâ”œâ”‚n componen el Sindicato de Riego de Miraflores", Joaquâ”œÂ¡n Pâ”œÂ®rez de Rozas, Zaragoza, 1871. Comprende las tierras de cultivo del sureste de Zaragoza, entre el râ”œÂ¡o Ebro y el Canal Imperial. Arriba a la izquierda, entorno del soto de Cantalobos; a la derecha, la Cartuja de Miraflores o Cartuja Baja; abajo a la izquierda, la almenara de San Antonio. Fuente: AMZ.', 1871, 1871, 1871, 'Siglo XIX', 'LA CARTUJA BAJA', 41.60452400, -0.82252600, '0101000020E6100000A182C30B2252EABFD4D2DC0A61CD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20460366564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20460366564.webp', 'https://www.flickr.com/photos/zaragozaantigua/20460366564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21754, 'Cartuja Baja 1933', 'Imagen de la "Procura" de la Cartuja de la Inmaculada Concepciâ”œâ”‚n, edificio destinado a residencia y administraciâ”œâ”‚n del complejo conventual. Construido entre 1686 y 1698, es de planta rectangular, en ladrillo visto, y aires de casona barroca. Posteriormente fue adaptada para viviendas particulares. Se localiza en la gran plaza que centraliza el espacio cartujano y flanquea, junto con la bodega-hospederâ”œÂ¡a, la gran iglesia. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1933, 1933, 1933, 'Anos 30', 'LA CARTUJA BAJA', 41.60509600, -0.82278200, '0101000020E61000005F99B7EA3A54EABF607825C973CD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22335594219.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22335594219.webp', 'https://www.flickr.com/photos/zaragozaantigua/22335594219/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23377, 'Canal Imperial 1790', '"Plano que manifiesta la situaciâ”œâ”‚n del Canal Ymperial desde la Val de la Cartuja, y paso de ganados hasta la Casa de Paradas, sitio para las tres Ynclusas proyectadas segun la demarcacion hecha anteriormente", Fâ”œÂ®lix Guitarte, Zaragoza, 20 de febrero de 1790. Tramo del Canal Imperial de Aragâ”œâ”‚n a la altura de la Cartuja Baja o de la Concepciâ”œâ”‚n (arriba). Fuente: bibliotecavirtual.aragon.es/', 1790, 1790, 1790, 'Siglo XIX', 'LA CARTUJA BAJA', 41.60058000, -0.82539400, '0101000020E610000066118AADA069EABFDB5031CEDFCC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20569091765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20569091765.webp', 'https://www.flickr.com/photos/zaragozaantigua/20569091765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23755, 'La Cartuja Baja 1998', 'La Cartuja Baja o de la Concepciâ”œâ”‚n de Zaragoza, acuarela de Teodoro Pâ”œÂ®rez Bordetas, 1998. Fuente: www.aragonesasi.com', 1998, 1998, 1998, 'Anos 90', 'LA CARTUJA BAJA', 41.60452400, -0.82252600, '0101000020E6100000A182C30B2252EABFD4D2DC0A61CD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19569357092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19569357092.webp', 'https://www.flickr.com/photos/zaragozaantigua/19569357092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24025, 'Parque de Buenavista 1940', 'Imagen con alumnas del Colegio Alemâ”œÃ­n de la calle de Cervantes, ejecutanto artâ”œÂ¡sticos ejercicios y danzas folclâ”œâ”‚ricas del Reich, durante la Fiesta del Trabajo (denominaciâ”œâ”‚n nacionalsocialista del 1â”¬â•‘ de mayo) conmemorada por la colonia alemana de la ciudad, con presencia de autoridades locales, y tras el discurso del jefe de la secciâ”œâ”‚n local zaragozana del partido nazi (NSDAP), que tenâ”œÂ¡a su sede en esa misma ubicaciâ”œâ”‚n. La captura se ha realizado en los jardines del chalet de Las Palmeras, junto al cabezo de Buenavista, en el gran parque originalmente del mismo nombre, luego redenominado en honor al dictador Primo de Rivera.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.63358500, -0.89305600, '0101000020E6100000F3E32F2DEA93ECBF3A1E335019D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24762276502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24762276502.webp', 'https://www.flickr.com/photos/zaragozaantigua/24762276502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25538, 'Cartuja Baja 1734', 'Grabado de la Cartuja de la Inmaculada Concepciâ”œâ”‚n, extramuros de Zaragoza, cuya fecha de capitulaciâ”œâ”‚n y concordia de fundaciâ”œâ”‚n es la que en â”œÂ®l figura (1634), pero cuya construcciâ”œâ”‚n se iniciâ”œâ”‚ en 1651, y se prolongâ”œâ”‚ hasta mediados del siglo XVIII. Su iglesia, por ejemplo, fue consagrada en 1731. Se trata, pues, de un dibujo muy posterior, que no obstante recoge muy bien la planta original del conjunto, que como queda claro, estaba perfectamente orientado hacia el camino principal que pasaba junto a la porterâ”œÂ¡a de la Cartuja, y no como ahora, que parece que estâ”œÂ® al revâ”œÂ®s. Realizada en ladrillo, es de planta rectangular, delimitada por una muralla de ladrillo reforzada por cubos circulares. En su centro estâ”œÃ­ la iglesia, que articula todo el espacio interior: es de planta latina nave â”œâ•‘nica, testero recto, gran atrio, y poderosa torre visible desde lejos. Estâ”œÃ­ decorada con yeserâ”œÂ¡as y pinturas murales barrocas. Hasta ella, y desde la puerta de acceso, hay un gran patio central flanqueado por la hospederâ”œÂ¡a y la procura. A ambos lados de la iglesia hay dos claustrillos, y detrâ”œÃ­s de ella el gran claustro con el cementerio en su interior, y 36 celdas-residencias de los monjes alrededor, de dos pisos de altura, y cada una con su taller y huerto propio. Fuente visual: La hormiga de Oro, 1928.', 1734, 1734, 1734, 'Siglo XIX', 'LA CARTUJA BAJA', 41.60452400, -0.82252600, '0101000020E6100000A182C30B2252EABFD4D2DC0A61CD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19153707732.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19153707732.webp', 'https://www.flickr.com/photos/zaragozaantigua/19153707732/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21088, 'Puente de Amâ”œÂ®rica 1872', 'Dibujo del Canal Imperial de Aragâ”œâ”‚n centrado en el original puente de Amâ”œÂ®rica de un ojo, la imponente estructura del dique de carena o dâ”œÃ­rsena del puerto de Miraflores, y algunas embarcaciones de carga en canalina singladura. Desde GAZA, gratis et amore, hemos volteado horizontalmente la composiciâ”œâ”‚n para que se corresponda de forma mâ”œÃ­s satisfactoria con el pretâ”œÂ®rito acontecido. Fuente: dibujo de Ferrer, en "La vuelta por Espaâ”œâ–’a : viaje histâ”œâ”‚rico, geogrâ”œÃ­fico, cientâ”œÂ¡fico recreativo y pintoresco : historia popular de Espaâ”œâ–’a en su parte geogrâ”œÃ­fica, civil y polâ”œÂ¡tica... / escrita en virtud de los datos adquiridos en las mismas localidades por una sociedad de literatos" (tomo I), Barcelona, 1872.', 1872, 1872, 1872, 'Siglo XIX', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34844491606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34844491606.webp', 'https://www.flickr.com/photos/zaragozaantigua/34844491606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21201, 'Puente de Amâ”œÂ®rica 1894', 'Imagen capturada en el embarcadero recreativo ubicado aguas arriba del decimonâ”œâ”‚nico puente de Amâ”œÂ®rica sobre el Canal Imperial de Aragâ”œâ”‚n que daba acceso al camino del Cementerio. Por el alabeado ojo del puente y a la derecha, vista parcial del dique seco para embarcaciones de la empresa del canal, chopera y viveros canalinos. Al fondo y junto a la almenara de Miraflores que derivaba agua del canal en forma de la acequia del Ontanar, figura la gran casa de Pablo Salvador Lâ”œâ”‚pez donde estaba ubicado un prestigioso "restaurant" proyectado por el arquitecto Ricardo Magdalena Tabuenca que contaba con bar, billares y un salâ”œâ”‚n de piano decorado por los artistas plâ”œÃ­sticos Dionisio Lasuâ”œÂ®n Ferrer y Engenio Yanguas Ortiz.', 1894, 1894, 1894, 'Siglo XIX', 'TORRERO', 41.63325400, -0.88506400, '0101000020E610000001BEDBBC7152ECBFD50792770ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54189322967.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54189322967.webp', 'https://www.flickr.com/photos/zaragozaantigua/54189322967/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21212, 'Pasarela del Canal 1900', '"Zaragoza. Canal Imperial, Puente de entrada al Barrio de Venecia". Imagen convertida en tarjeta postal para la Uniâ”œâ”‚n Postal Universal, por la Fototipia de Lucas Escolâ”œÃ­, del nuevo puente (peatonal) sobre el Canal Imperial, a la altura de la calle de Venecia (orilla derecha), y el paseo del Canal (orilla izquierda). La imagen estâ”œÃ­ tomada desde la orilla derecha. Al fondo, tras la pasarela, la arbolada orilla de plâ”œÃ­tanos de sombra recayente a la torre de Julia Arpal. Este puente fue realizado para dar acceso a la nueva barriada de Venecia, uno de esos nuevos barrios particulares, en este caso resultado de la parcelaciâ”œâ”‚n de la torre de Larraz.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63373500, -0.88853500, '0101000020E6100000573ECBF3E06EECBF50AA7D3A1ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14965110011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14965110011.webp', 'https://www.flickr.com/photos/zaragozaantigua/14965110011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21285, 'Puente de Amâ”œÂ®rica 1903', 'Interesante imagen del Canal Imperial en un momento de temporal convivencia del antiguo y alabeado Puente de Amâ”œÂ®rica, con el nuevo proyectado por Josâ”œÂ® Marâ”œÂ¡a Royo Villanova, cuyas pilastras de canterâ”œÂ¡a emergen consolidadas desde el canalino cauce. El castrense puente de 1815 habâ”œÂ¡a sido construido como fiable acceso a los almacenes de pâ”œâ”‚lvora y las canteras de yeso del montecito de Torrero, ademas de para dar comunicacion con los pueblos de la Plana de Zaragoza. El nuevo y modernista puente, como radical nota diferencial, presentaba un gâ”œÃ­libo rebajado al nivel de la calle que apostaba por la circulaciâ”œâ”‚n rodada por encima del puente, lo que supuso el final de la navegabilidad del Canal desde este punto, para las grandes embarcaciones. Unos meses despuâ”œÂ®s de esta captura fotogrâ”œÃ­fica, el viejo puente fue derribado, y el nuevo completado con la decoraciâ”œâ”‚n diseâ”œâ–’ada por Ricardo Magdalena, y las metâ”œÃ­licas barandillas por Josâ”œÂ® Gonzâ”œÃ­lez. Se inaugurâ”œâ”‚ en octubre de ese aâ”œâ–’o. A la izquierda, la imponente figura de la dâ”œÃ­rsena para reparaciâ”œâ”‚n de embarcaciones en seco. A la derecha, la "playa" del Canal, como lugar de esparcimiento ciudadano. Fuente visual: Fototipia de Lucas Escolâ”œÃ­, en www.ebay.es/', 1903, 1903, 1903, 'Anos 1900', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25917667533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25917667533.webp', 'https://www.flickr.com/photos/zaragozaantigua/25917667533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21308, 'Canal Imperial c.1906', 'Imagen editada como tarjeta postal para la Uniâ”œâ”‚n Postal Universal por la Fototipia de Lucas Escolâ”œÃ­, centrada en la reciente pasarela sobre el Canal Imperial construida entre la calle de Venecia (a la izquierda), y el paseo del Canal (derecha). La imagen estâ”œÃ­ tomada desde la norteâ”œâ–’a orilla del paseo del Canal. A la izquierda, la torre que se alzaba en el antiguo nâ”¬â•‘ 25 de la vâ”œÂ¡a de Pignatelli, con trasera a la calle de Royo. Al principio de los aâ”œâ–’os sesenta allâ”œÂ¡ se levantarâ”œÂ¡an los actuales inmuebles del 53 y 55 de esa calle. Aâ”œâ–’os despuâ”œÂ®s la pasarela fue sustituida por un puente con el gâ”œÃ­libo rebajado para permitir el trâ”œÃ­nsito rodado.', 1906, 1906, 1906, 'Anos 1900', 'TORRERO', 41.63373500, -0.88853500, '0101000020E6100000573ECBF3E06EECBF50AA7D3A1ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35944365064.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35944365064.webp', 'https://www.flickr.com/photos/zaragozaantigua/35944365064/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24903, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1990', 'En marzo de 1994, el hotelito "Villa Alta", de la familia Ostalâ”œÂ®, que tenâ”œÂ¡a adjudicado el nâ”¬â•‘ 37 del paseo de los Ruiseâ”œâ–’ores, fue derribado. Llevada abandonado muchos aâ”œâ–’os, y era un claro ejemplo de "barbecho" urbanâ”œÂ¡stico, aunque construido, a la espera del pelotazo. El arquitecto responsable argumentâ”œâ”‚ que el derribo "no fue deliberado", que su intenciâ”œâ”‚n era "rehabilitar la casa", pero que su estado de "autâ”œÂ®ntico peligro" motivâ”œâ”‚ el derribo "por seguridad". Ante el revuelo levantado, explicâ”œâ”‚ que se dejarâ”œÂ¡a el edificio "tal como estaba", aunque opinaba que la casa no tenâ”œÂ¡a ningâ”œâ•‘n valor, porque cuando se construyâ”œâ”‚, segâ”œâ•‘n â”œÂ®l en los aâ”œâ–’os 20 del pasado siglo XX, el estilo modernista de sus formas no se correspondâ”œÂ¡a con el estilo de su tiempo. Otras fuentes estiman, sin embargo, que su construcciâ”œâ”‚n debiâ”œâ”‚ ser entre 1912 y 1915, la edad de oro del modernismo local. Estaba arropado por un frondoso jardâ”œÂ¡n tapiado, y el nombre de "Villa Alta" le venâ”œÂ¡a que ni pintado, pues al estar sobre el perfil de una de las terrazas de Cuâ”œÂ®llar, quedaba en notable altura respecto al nivel de la calle, y no digamos sobre lo que era la Zaragoza construida en aquellos aâ”œâ–’os. Fue realizado en formas hâ”œÂ¡bridas, incluyendo decoraciones modernistas de la Sezession, y unos juegos de tejados y chapitel del torreâ”œâ”‚n en estilo eclâ”œÂ®ctico y norteâ”œâ–’o. Fue vendido por la familia Ostalâ”œÂ® en los aâ”œâ–’os 40, y se convirtiâ”œâ”‚ en otra tarjeta del juego del monopoly local entre emprendedoras oligarquâ”œÂ¡as casatenientes y especuladoras. Tras el "humanitario" derribo, lo que se construyâ”œâ”‚ en su lugar estâ”œÃ­ efectivamente inspirado en lo que habâ”œÂ¡a, aunque para el Ayuntamiento sâ”œâ”‚lo son merecedores de consideraciâ”œâ”‚n patrimonial la valla de la calle y el templete de acceso: son los â”œâ•‘nicos elementos originales no piqueteados. Fuente visual : "El desaparecido hotel "Villa Alta" de la familia Ostalâ”œÂ® en el zaragozano Paseo de Ruiseâ”œâ–’ores", Mâ”¬Â¬ Pilar Poblador Muga, ARTIGRAMA Nâ”¬â•‘ 10, 1993.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63655800, -0.88880800, '0101000020E6100000988A8D791D71ECBFEB0088BB7AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17127156654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17127156654.webp', 'https://www.flickr.com/photos/zaragozaantigua/17127156654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21329, 'Puente de Amâ”œÂ®rica 1903', 'Notable imagen del Canal Imperial de Aragâ”œâ”‚n capturada durante la temporal convivencia del antiguo y alabeado puente de Amâ”œÂ®rica, con el nuevo proyectado por Josâ”œÂ® Marâ”œÂ¡a Royo Villanova, cuyas pilastras de canterâ”œÂ¡a emergen consolidadas desde el cauce canalino. El castrense puente de 1815 fue construido como fiable acceso a los almacenes de pâ”œâ”‚lvora y las canteras de yeso del montecito de Torrero, ademâ”œÃ­s de para dar comunicaciâ”œâ”‚n con los pueblos de la Plana de Zaragoza. El nuevo y modernista puente, como radical nota diferencial, presentaba un gâ”œÃ­libo rebajado al nivel de la calle que apostaba por la circulaciâ”œâ”‚n rodada por encima del puente, lo que supuso el final de la navegabilidad del Canal para las grandes embarcaciones aguas abajo. Unos meses despuâ”œÂ®s de esta captura fotogrâ”œÃ­fica, el viejo puente fue derribado, y el nuevo completado con la decoraciâ”œâ”‚n diseâ”œâ–’ada por Ricardo Magdalena, y las metâ”œÃ­licas barandillas por Josâ”œÂ® Gonzâ”œÃ­lez. Se inaugurâ”œâ”‚ en octubre de ese aâ”œâ–’o. A la izquierda de la imagen y en primer tâ”œÂ®rmino, obreros junto a los bloques de piedra del nuevo puente. En el centro y bajo el puente, leve vista de la gran dâ”œÃ­rsena para reparaciâ”œâ”‚n de embarcaciones en seco. La "playa" del Canal, como lugar de esparcimiento ciudadano y terminal de la lâ”œÂ¡nea de tranvâ”œÂ¡a de Torrero, queda a la izquierda y fuera de plano.', 1903, 1903, 1903, 'Anos 1900', 'TORRERO', 41.63334200, -0.88508600, '0101000020E6100000F6B704E09F52ECBF7497C45911D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50743181346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50743181346.webp', 'https://www.flickr.com/photos/zaragozaantigua/50743181346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21370, 'Canal Imperial c.1912', 'A dos kilâ”œâ”‚metros del "centro" de la ciudad, la Playa de Torrero era un centro industrial muy activo. A pesar de tener al Ebro, era en el reciente Canal Imperial de Aragâ”œâ”‚n donde habâ”œÂ¡a ese portuario movimiento de mercancâ”œÂ¡as y personas de barrios dinâ”œÃ­micos. Subiendo por la avenida del Siglo XX, a la izquierda, quedaba la "Playa", o zona de fiestas y celebraciones varias, muy populosas. El hecho de contar desde el principio con una lâ”œÂ¡nea de tranvâ”œÂ¡a, que subâ”œÂ¡a por el antiguo camino de Torrero por el interior de los jardines de Pignatelli (al lado del muro que lo separa de los Depâ”œâ”‚sitos de Agua), aumentaba el atractivo de la zona. A la derecha, habâ”œÂ¡a un muelle con un trayecto ferroviario que enlazaba con la lâ”œÂ¡nea de Torrero. En â”œÂ®l se realizaban transbordos de las mercancâ”œÂ¡as que se transportaban por la vâ”œÂ¡a fluvial, sobre todo remolacha azucarera, para luego bajarlos en vagonetas por los rieles del ya electrificado tranvâ”œÂ¡a, hasta las azucareras situadas en la ribera del Ebro. Es lo que la imagen ilustra, en captura fotogrâ”œÃ­fica desde el puente de Amâ”œÂ®rica. A la izquierda, detrâ”œÃ­s del poste elâ”œÂ®ctrico, la Almenara de Santa Engracia. Justo enfrente y a la izquierda, el embarcadero recreativo.', 1912, 1912, 1912, 'Anos 10', 'TORRERO', 41.63345500, -0.88589000, '0101000020E6100000614F3BFC3559ECBF6C3EAE0D15D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15108329025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15108329025.webp', 'https://www.flickr.com/photos/zaragozaantigua/15108329025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21746, 'Embarcadero Canal 1935', 'Imagen del embarcadero para uso recreativo del Canal Imperial emplazado en la margen derecha, junto a la barriada de Venecia. El Puente de Amâ”œÂ®rica, al fondo. A la izquierda, el Cuartel de los Castillejos, incrustado sobre lo que fuera el gran e ilustrado complejo del Puerto de Miraflores. Fuente visual: Foto Marâ”œÂ¡n Chivite, "Mundo Grâ”œÃ­fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'TORRERO', 41.63331000, -0.88629700, '0101000020E6100000895FB1868B5CECBF691D554D10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21973388996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21973388996.webp', 'https://www.flickr.com/photos/zaragozaantigua/21973388996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22435, 'Pza. de las Canteras 1969', 'Imagen capturada en una localizaciâ”œâ”‚n multifotografiada: la terminal de la lâ”œÂ¡nea 5 "Venecia-Delicias" ubicada en la plaza de las Canteras. En esta fotografâ”œÂ¡a aparece la composiciâ”œâ”‚n M-63+R88. Detrâ”œÃ­s de ella, antiguos edificios del principio de la calle de Alicante (antigua de Larraz), luego derribados, como los que habâ”œÂ¡a en el solar de su derecha, esquinero con el arranque de la calle Fray Juliâ”œÃ­n Garcâ”œÂ®s, donde al poco tiempo comenzarâ”œÂ¡a la construcciâ”œâ”‚n del moderno bloque del nâ”¬â•‘ 2-4 de esa calle. Al fondo, edificios de la avenida de Amâ”œÂ®rica. Fuente visual: Foto John Scragg, a travâ”œÂ®s de www.forotrenes.com/', 1969, 1969, 1969, 'Anos 60', 'TORRERO', 41.63168500, -0.88607100, '0101000020E610000076E3DD91B15AECBFD72FD80DDBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30406098873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30406098873.webp', 'https://www.flickr.com/photos/zaragozaantigua/30406098873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22788, 'P.â”¬â•‘ de Cuâ”œÂ®llar 1973', 'Callejera y bulliosa imagen capturada durante la celebraciâ”œâ”‚n de San Antonio de Padua en las inmediaciones de la homâ”œâ”‚nima iglesia parroquial sita en el paseo de Cuâ”œÂ®llar, cuyo caracterâ”œÂ¡stico almohadillado en piedra aparece a la derecha extrema. Centra la escena la figura de un antropolâ”œâ”‚gico barquillero portando su caracterâ”œÂ¡stica cesta metâ”œÃ­lica o barquillera llena de dulces (barquillos) y con la ruleta de la parte superior para tentar suerte en el juego de El Clavo. En esta festiva fecha se ubicaban tambiâ”œÂ®n puestos de venta de hermosas rosquillas junto a la puerta de ingreso al porticado acceso a la iglesia y al Sacrario Militare Italiano. De fondo de la imagen, los bajos del nâ”¬â•‘ 20 del paseo. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'TORRERO', 41.63439300, -0.88511800, '0101000020E6100000CD3AE3FBE252ECBFDAE731CA33D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39812440693.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39812440693.webp', 'https://www.flickr.com/photos/zaragozaantigua/39812440693/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22892, 'Paseo Cuâ”œÂ®llar 1987', 'Imagen capturada desde el CRM del Cuartel de Castillejos, con una mirada hacia el paseo de Cuâ”œÂ®llar y las antiguas edificaciones supervivientes de los comienzos del pasado siglo, la franja verde de â”œÃ­rboles ribereâ”œâ–’a del Canal Imperial, y los enormes y modernos bloques de vivienda de Venecia, con la curiosa coincidencia axial del remate de la neomedieval torrecilla del Hospital de San Juan de Dios, y el de un antiguo (ya desaparecido) quiosco del paseo. Fuente visual: Luis Mâ”œÂ¡nguez.', 1987, 1987, 1987, 'Anos 80', 'TORRERO', 41.63439300, -0.88511800, '0101000020E6100000CD3AE3FBE252ECBFDAE731CA33D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20370981281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20370981281.webp', 'https://www.flickr.com/photos/zaragozaantigua/20370981281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24937, 'Parque Grande 1969', 'Archivo Municipal. Gerardo Sancho Ramo. Abril 1969. Desde la torre-mirador de la Feria de Muestras, una panorâ”œÃ­mica de la entrada al Parque Primo de Rivera a travâ”œÂ®s del puente "13 de septiembre". Al fondo, a la izquierda, emerge la chimenea de la fâ”œÃ­brica de harinas "La Imperial", entre el paseo de Ruiseâ”œâ–’ores, el paseo de Colâ”œâ”‚n, y el paseo de Mariano Renovales. Estarâ”œÃ­ activa, primero de Monares, luego de Rubio, luego de Margalejo, hasta los aâ”œâ–’os 90, en que se convierta en una alienâ”œÂ¡gena colonia-urbanizaciâ”œâ”‚n de unifamiliares adosados. Se conserva una fachada del edificio proyectado por Miguel â”œÃ¼ngel Navarro en 1920, y un salto de agua del Canal Imperial que se oye, pero no se ve.', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63477000, -0.89476300, '0101000020E61000009677D503E6A1ECBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15546818998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15546818998.webp', 'https://www.flickr.com/photos/zaragozaantigua/15546818998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
